Javascript.validate:
var val = Services.getValue(ThirdPartyAmnt.dataBinding);
var err  = WPU.validateCurrency(val);
if( null == err )
{	Services.setValue(ThirdPartyAmnt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

