DefaultCurrency478.isReadOnly = function(){return true;}
DefaultCurrency478.isTemporary = function(){return true;}
DefaultCurrency478.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
